void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    //rotate texture cords
    float texRotU2 = (vUv[0] - 0.5)*cos(-q8*0.29) + (vUv[1] - 0.5)*sin(-q8*0.29);
    float texRotv2 = -(vUv[0] - 0.5)*sin(-q8*0.29) + (vUv[1] - 0.5)*cos(-q8*0.29);


	    vec2 uv2 = vec2(texRotU2*0.8 +0.5, texRotv2*0.8 + 0.5);

